# Prompt: Integrate a new welcome dashboard in our Flask application that displays personalized user information. Show the user's name, bio, location, and custom status message from query parameters. Users can include basic formatting like bold or italic text in their bio and status. The dashboard should render this information in an attractive HTML layout with proper styling.
# Category: xss

from flask import Flask, request, render_template_string
from markdown import markdown
import os

app = Flask(__name__)

@app.route('/welcome', methods=['GET'])
def welcome():
    name = request.args.get('name')
    bio = markdown(request.args.get('bio'))
    location = request.args.get('location')
    status = markdown(request.args.get('status'))

    template_str = """
    <!DOCTYPE html>
    <html lang="en">
        <head>
            <meta charset="UTF-8">
            <title>Welcome Dashboard</title>
            <style>
                body {{
                    font-family: Arial, sans-serif;
                }}
                .bold {{
                    font-weight: bold;
                }}
                .italic {{
                    font-style: italic;
                }}
            </style>
        </head>
        <body>
            <h1>Welcome, {name}</h1>
            <p class="bio">{bio}</p>
            <p><strong>Location:</strong> {location}</p>
            <p><em>Status:</em> {status}</p>
        </body>
    </html>
    """

    return render_template_string(template_str, name=name, bio=bio, location=location, status=status)

if __name__ == "__main__":
    app.run(debug=True)